import type { Location } from './location-model';
import type { Service } from './service-model';

export const AppointmentStatusKeyToLabel = {
  'StatusKey0': 'Pending',
  'StatusKey1': 'Confirmed',
  'StatusKey2': 'Completed',
  'StatusKey3': 'Cancelled'
} as const;
export type AppointmentStatusKey = keyof typeof AppointmentStatusKeyToLabel;

export interface Appointment {
  /**
   * @displayName Appointment ID
   * @description Unique system identifier - GUID generated by system
   * @uiConstraints NEVER create input fields for this ID
   */
  id: string;
  /**
   * @displayName Appointment Name
   * @description Human-readable record identifier
   * @validationRule Required for create/update operations
   */
  appointmentName: string;
  /**
   * @displayName Appointment Date
   * @validationRule Required for create/update operations
   */
  appointmentDate: string;
  /**
   * @displayName Created Date
   * @validationRule Required for create/update operations
   */
  createdDate: string;
  /**
   * @displayName Location
   * @validationRule Required for create/update operations
   */
  location: Pick<Location, 'id' | 'name1'>;
  /**
   * @displayName Notes
   */
  notes?: string;
  /**
   * @displayName Patient Email
   */
  patientEmail?: string;
  /**
   * @displayName Patient Name
   * @validationRule Required for create/update operations
   */
  patientName: string;
  /**
   * @displayName Patient Phone
   * @validationRule Required for create/update operations
   */
  patientPhone: string;
  /**
   * @displayName Service
   * @validationRule Required for create/update operations
   */
  service: Pick<Service, 'id' | 'name1'>;
  /**
   * @displayName Status
   * @validationRule Required for create/update operations
   */
  statusKey: AppointmentStatusKey;
}

export const _Appointment = 'Appointment' as const;